/**
 * Program 18: Threading in Java
 * Description: Implementation of Threads including Priority, Naming and Daemon.
 */
class WorkerThread extends Thread {
    public WorkerThread(String name) {
        super(name);
    }

    public void run() {
        System.out.println("Thread '" + this.getName() + "' has started execution.");
        if(this.isDaemon()) {
            System.out.println("Thread '" + this.getName() + "' is a Daemon Thread.");
        } else {
            System.out.println("Thread '" + this.getName() + "' is a User Thread.");
        }
        System.out.println("Thread Priority is: " + this.getPriority() + "\n");
    }
}

public class AdvancedThreading {
    public static void main(String args[]) {
        System.out.println("--- Java Multithreading & Daemon Threads by {studentName} ---\n");

        WorkerThread t1 = new WorkerThread("HighPrior-Thread");
        WorkerThread t2 = new WorkerThread("Background-Daemon");
        WorkerThread t3 = new WorkerThread("Standard-Thread");

        // Setting Priorities
        t1.setPriority(Thread.MAX_PRIORITY); // Priority 10
        t3.setPriority(Thread.NORM_PRIORITY); // Priority 5

        // Set as Daemon before starting
        t2.setDaemon(true);

        // Start Threads
        t1.start();
        t2.start();
        t3.start();

        try {
            // Waiting for threads to finish so output displays nicely
            t1.join();
            t2.join();
            t3.join();
        } catch(InterruptedException e) {
            System.out.println("Main thread interrupted.");
        }
    }
}

